import React from 'react'

function Recommendcarousel() {

  const CardCarousel = () => {
    const cards = [
      { id: 1, title: "Deva", imgSrc: "..." },
      { id: 2, title: "Deva", imgSrc: "..." },
      { id: 3, title: "Deva", imgSrc: "..." },
      { id: 4, title: "Deva", imgSrc: "..." },
      { id: 5, title: "Deva", imgSrc: "..." },
      { id: 6, title: "Deva", imgSrc: "..." },
      { id: 7, title: "Deva", imgSrc: "..." },
      { id: 8, title: "Deva", imgSrc: "..." },
    ];
    return (
      <Carousel>
        {[0, 4].map((startIndex) => (
          <Carousel.Item key={startIndex}>
            <div className="d-flex justify-content-around">
              {cards.slice(startIndex, startIndex + 4).map((card) => (
                <div className="card" key={card.id} style={{ width: "18rem" }}>
                  <img src={card.imgSrc} className="card-img-top" alt={card.title} />
                  <div className="card-body">
                    <h5 className="card-title">{card.title}</h5>
                  </div>
                </div>
              ))}
            </div>
          </Carousel.Item>
        ))}
      </Carousel>
    );
  };
}

export default Recommendcarousel;
